// // This module implements a 4-input multiplexer with an enable input. It selects one of four input signals based on the 2-bit selection signal S and the enable signal E. If E is 0, the output Y is 0. Otherwise, Y is the value of the input signal selected by S.
module mux4(input [7:0] A, input [7:0] B, input [7:0] C, input [7:0] D, input E, input [1:0] S, output reg [7:0] Y);

always @(*)
begin
    if (E == 0)
        Y = 0;
    else if (S == 2'b00)
        Y = A;
    else if (S == 2'b01)
        Y = B;
    else if (S == 2'b10)
        Y = C;
    else if (S == 2'b11)
        Y = D;
end

endmodule
